// Experimental visual effects. Each can be turned off with a single boolean;
// they are intentionally easy to revoke.
export const EFFECTS = {
  // G: crossfade the character sprite when the expression changes.
  expressionTransition: true,
  // H: reveal content with a slow expand as it scrolls into view.
  scrollReveal: true,
  // I: stagger repeated widgets (cards) with randomized delays.
  cardStagger: true,
  // J: a soft point-light that follows the cursor across the page.
  cursorLight: true,
}
